14	/**
15	 * Centralized object-level authorization.
16	 * Policy: admin can access all; non-admin only own records. Return 404 for unauthorized.
17	 */
18	@Service
19	public class ResourceAuthorizationService {
20	
21	    private final UserService userService;
22	    private final SavedSearchRepository savedSearchRepo;
23	    private final SearchSnapshotRepository snapshotRepo;
24	    private final TalentPoolRepository talentPoolRepo;
25	    private final ExportJobRepository exportJobRepo;
26	    private final ImportJobRepository importJobRepo;
27	    private final PaymentTransactionRepository paymentRepo;
28	
29	    public ResourceAuthorizationService(UserService userService,
30	                                         SavedSearchRepository savedSearchRepo,
31	                                         SearchSnapshotRepository snapshotRepo,
32	                                         TalentPoolRepository talentPoolRepo,
33	                                         ExportJobRepository exportJobRepo,
34	                                         ImportJobRepository importJobRepo,
35	                                         PaymentTransactionRepository paymentRepo) {
36	        this.userService = userService;
37	        this.savedSearchRepo = savedSearchRepo;
38	        this.snapshotRepo = snapshotRepo;
39	        this.talentPoolRepo = talentPoolRepo;
40	        this.exportJobRepo = exportJobRepo;
41	        this.importJobRepo = importJobRepo;
42	        this.paymentRepo = paymentRepo;
43	    }
44	
45	    public boolean isAdmin(Authentication auth) {
46	        return auth.getAuthorities().stream()
47	                .map(GrantedAuthority::getAuthority)
48	                .anyMatch(a -> a.equals("ROLE_ADMINISTRATOR"));
49	    }
50	
51	    public Long resolveUserId(Authentication auth) {
52	        return userService.findByUsername(auth.getName())
53	                .map(User::getId)
54	                .orElseThrow(() -> new ResourceNotFoundException("User not found"));
55	    }
56	
57	    @Transactional(readOnly = true)
58	    public SavedSearch authorizeSavedSearch(Long id, Authentication auth) {
59	        if (isAdmin(auth)) {
60	            return savedSearchRepo.findById(id)
61	                    .orElseThrow(() -> new ResourceNotFoundException("Saved search not found"));
62	        }
63	        Long userId = resolveUserId(auth);
64	        return savedSearchRepo.findByIdAndCreatedBy(id, userId)
65	                .orElseThrow(() -> new ResourceNotFoundException("Saved search not found"));
66	    }
67	
68	    @Transactional(readOnly = true)
69	    public SearchSnapshot authorizeSnapshot(Long id, Authentication auth) {
70	        if (isAdmin(auth)) {
71	            return snapshotRepo.findByIdWithResults(id)
72	                    .orElseThrow(() -> new ResourceNotFoundException("Search snapshot not found"));
73	        }
74	        Long userId = resolveUserId(auth);
75	        return snapshotRepo.findByIdAndCreatedByWithResults(id, userId)
76	                .orElseThrow(() -> new ResourceNotFoundException("Search snapshot not found"));
77	    }
78	
79	    @Transactional(readOnly = true)
80	    public TalentPool authorizeTalentPool(Long id, Authentication auth) {
81	        if (isAdmin(auth)) {
82	            return talentPoolRepo.findByIdWithCandidates(id)
83	                    .orElseThrow(() -> new ResourceNotFoundException("Talent pool not found"));
84	        }
85	        Long userId = resolveUserId(auth);
86	        return talentPoolRepo.findByIdAndCreatedByWithCandidates(id, userId)
87	                .orElseThrow(() -> new ResourceNotFoundException("Talent pool not found"));
88	    }
89	
90	    @Transactional(readOnly = true)
91	    public ExportJob authorizeExportJob(Long id, Authentication auth) {
92	        if (isAdmin(auth)) {
93	            return exportJobRepo.findById(id)
94	                    .orElseThrow(() -> new ResourceNotFoundException("Export job not found"));
95	        }
96	        Long userId = resolveUserId(auth);
97	        return exportJobRepo.findByIdAndCreatedBy(id, userId)
98	                .orElseThrow(() -> new ResourceNotFoundException("Export job not found"));
99	    }
100	
101	    @Transactional(readOnly = true)
102	    public ImportJob authorizeImportJob(Long id, Authentication auth) {
103	        if (isAdmin(auth)) {
104	            return importJobRepo.findById(id)
105	                    .orElseThrow(() -> new ResourceNotFoundException("Import job not found"));
106	        }
107	        Long userId = resolveUserId(auth);
108	        return importJobRepo.findByIdAndCreatedBy(id, userId)
109	                .orElseThrow(() -> new ResourceNotFoundException("Import job not found"));
110	    }
111	
112	    @Transactional(readOnly = true)
113	    public PaymentTransaction authorizePayment(Long id, Authentication auth) {
114	        return paymentRepo.findById(id)
115	                .orElseThrow(() -> new ResourceNotFoundException("Payment not found"));
116	    }
117	}
