3	import com.eaglepoint.workforce.entity.*;
4	import com.eaglepoint.workforce.enums.ImportStatus;
5	import com.eaglepoint.workforce.repository.*;
6	import org.apache.poi.ss.usermodel.*;
7	import org.apache.poi.xssf.usermodel.XSSFWorkbook;
8	import org.springframework.beans.factory.annotation.Value;
9	import org.springframework.scheduling.annotation.Async;
10	import org.springframework.stereotype.Service;
11	import org.springframework.transaction.annotation.Transactional;
12	import org.springframework.web.multipart.MultipartFile;
13	
14	import java.io.*;
15	import java.nio.file.Files;
16	import java.nio.file.Path;
17	import java.nio.file.Paths;
18	import java.security.MessageDigest;
19	import java.time.LocalDateTime;
20	import java.util.*;
21	
22	@Service
23	public class ImportService {
24	
25	    @Value("${app.import.storage-path:./imports}")
26	    private String storagePath;
27	
28	    private final ImportJobRepository importJobRepo;
29	    private final DepartmentRepository departmentRepo;
30	    private final TrainingCourseRepository courseRepo;
31	
32	    public ImportService(ImportJobRepository importJobRepo,
33	                          DepartmentRepository departmentRepo,
34	                          TrainingCourseRepository courseRepo) {
35	        this.importJobRepo = importJobRepo;
36	        this.departmentRepo = departmentRepo;
37	        this.courseRepo = courseRepo;
38	    }
39	
40	    @Transactional
41	    public ImportJob prepareImport(MultipartFile file, String importType, Long createdBy) throws Exception {
42	        String fingerprint = computeSha256(file.getInputStream());
43	
44	        if (importJobRepo.existsByFileFingerprint(fingerprint)) {
45	            ImportJob dup = new ImportJob();
46	            dup.setOriginalFileName(file.getOriginalFilename());
47	            dup.setImportType(importType);
48	            dup.setFileFingerprint(fingerprint);
49	            dup.setStatus(ImportStatus.DUPLICATE);
50	            dup.setCreatedBy(createdBy);
51	            dup.setErrorReport("This file has already been imported (SHA-256: " + fingerprint + ")");
52	            return importJobRepo.save(dup);
53	        }
54	
55	        Path dir = Paths.get(storagePath);
56	        Files.createDirectories(dir);
57	        String savedName = System.currentTimeMillis() + "_" + file.getOriginalFilename();
58	        Path savedPath = dir.resolve(savedName);
59	        file.transferTo(savedPath.toFile());
60	
61	        ImportJob job = new ImportJob();
62	        job.setOriginalFileName(file.getOriginalFilename());
63	        job.setImportType(importType);
64	        job.setFileFingerprint(fingerprint);
65	        job.setFilePath(savedPath.toString());
66	        job.setStatus(ImportStatus.QUEUED);
67	        job.setCreatedBy(createdBy);
68	        return importJobRepo.save(job);
69	    }
70	
71	    @Async("importExecutor")
72	    public void executeImport(Long jobId) {
73	        ImportJob job = importJobRepo.findById(jobId).orElse(null);
74	        if (job == null || job.getStatus() == ImportStatus.DUPLICATE) return;
75	
76	        job.setStatus(ImportStatus.VALIDATING);
77	        importJobRepo.save(job);
78	
79	        try {
80	            Path filePath = Paths.get(job.getFilePath());
81	            String fileName = job.getOriginalFileName().toLowerCase();
82	            List<String[]> rows;
83	
84	            if (fileName.endsWith(".xlsx") || fileName.endsWith(".xls")) {
85	                rows = readExcel(filePath);
86	            } else if (fileName.endsWith(".csv")) {
87	                rows = readCsv(filePath);
88	            } else {
89	                throw new RuntimeException("Unsupported file format. Use .xlsx, .xls, or .csv");
90	            }
91	
92	            if (rows.isEmpty()) {
93	                throw new RuntimeException("File is empty");
94	            }
95	
96	            job.setStatus(ImportStatus.IMPORTING);
97	            job.setTotalRows(rows.size() - 1); // exclude header
98	            importJobRepo.save(job);
99	
100	            String[] header = rows.get(0);
101	            validateHeaderSchema(job.getImportType(), header);
102	
103	            List<String> errors = new ArrayList<>();
104	            int successCount = 0;
105	
106	            for (int i = 1; i < rows.size(); i++) {
107	                String[] row = rows.get(i);
108	                try {
109	                    validateAndImportRow(job.getImportType(), header, row, i);
110	                    successCount++;
111	                } catch (Exception e) {
112	                    errors.add("Row " + (i + 1) + ": " + e.getMessage());
113	                }
114	            }
115	
116	            job.setSuccessRows(successCount);
117	            job.setErrorRows(errors.size());
118	            job.setErrorReport(errors.isEmpty() ? null : String.join("\n", errors));
119	            job.setStatus(errors.isEmpty() ? ImportStatus.COMPLETED : ImportStatus.COMPLETED_WITH_ERRORS);
120	            job.setCompletedAt(LocalDateTime.now());
121	        } catch (Exception e) {
122	            job.setStatus(ImportStatus.FAILED);
123	            job.setErrorReport(e.getMessage());
124	            job.setCompletedAt(LocalDateTime.now());
125	        }
126	        importJobRepo.save(job);
127	    }
128	
129	    @Transactional(readOnly = true)
130	    public List<ImportJob> findAll() {
131	        return importJobRepo.findAllByOrderByCreatedAtDesc();
132	    }
133	
134	    @Transactional(readOnly = true)
135	    public List<ImportJob> findByUser(Long userId) {
136	        return importJobRepo.findByCreatedByOrderByCreatedAtDesc(userId);
137	    }
138	
139	    @Transactional(readOnly = true)
140	    public Optional<ImportJob> findById(Long id) {
141	        return importJobRepo.findById(id);
142	    }
143	
144	    private static final Map<String, Set<String>> REQUIRED_HEADERS = Map.of(
145	            "departments", Set.of("Code", "Name"),
146	            "courses", Set.of("Code", "Name")
147	    );
148	
149	    private static final Map<String, Set<String>> ALLOWED_HEADERS = Map.of(
150	            "departments", Set.of("Code", "Name", "Head Name", "Active"),
151	            "courses", Set.of("Code", "Name", "Description", "Credit Hours", "Mandatory", "Active")
152	    );
153	
154	    void validateHeaderSchema(String importType, String[] header) {
155	        Set<String> required = REQUIRED_HEADERS.get(importType);
156	        if (required == null) {
157	            throw new RuntimeException("Unknown import type: " + importType);
158	        }
159	        Set<String> allowed = ALLOWED_HEADERS.get(importType);
160	        Set<String> actual = new LinkedHashSet<>();
161	        for (String h : header) actual.add(h.trim());
162	
163	        List<String> missing = new ArrayList<>();
164	        for (String r : required) {
165	            if (!actual.contains(r)) missing.add(r);
166	        }
167	        if (!missing.isEmpty()) {
168	            throw new RuntimeException("Missing required column(s): " + String.join(", ", missing)
169	                    + ". Expected schema: " + required);
170	        }
171	
172	        List<String> unknown = new ArrayList<>();
173	        for (String a : actual) {
174	            if (!allowed.contains(a)) unknown.add(a);
175	        }
176	        if (!unknown.isEmpty()) {
177	            throw new RuntimeException("Unknown column(s): " + String.join(", ", unknown)
178	                    + ". Allowed columns: " + allowed);
179	        }
180	    }
181	
182	    @Transactional
183	    void validateAndImportRow(String importType, String[] header, String[] row, int rowIndex) {
184	        switch (importType) {
185	            case "departments" -> importDepartmentRow(header, row, rowIndex);
186	            case "courses" -> importCourseRow(header, row, rowIndex);
187	            default -> throw new RuntimeException("Unknown import type: " + importType);
188	        }
189	    }
190	
191	    private void importDepartmentRow(String[] header, String[] row, int rowIndex) {
192	        Map<String, String> map = zipToMap(header, row);
193	        String code = requireField(map, "Code", rowIndex);
194	        String name = requireField(map, "Name", rowIndex);
195	
196	        if (departmentRepo.existsByCode(code)) {
197	            Department existing = departmentRepo.findByCode(code).orElseThrow();
198	            existing.setName(name);
199	            existing.setHeadName(map.getOrDefault("Head Name", existing.getHeadName()));
200	            departmentRepo.save(existing);
201	        } else {
202	            Department dept = new Department();
203	            dept.setCode(code);
204	            dept.setName(name);
205	            dept.setHeadName(map.get("Head Name"));
206	            dept.setActive(!"No".equalsIgnoreCase(map.get("Active")));
207	            departmentRepo.save(dept);
208	        }
209	    }
210	
211	    private void importCourseRow(String[] header, String[] row, int rowIndex) {
212	        Map<String, String> map = zipToMap(header, row);
213	        String code = requireField(map, "Code", rowIndex);
214	        String name = requireField(map, "Name", rowIndex);
215	
216	        if (courseRepo.existsByCode(code)) {
217	            TrainingCourse existing = courseRepo.findByCode(code).orElseThrow();
218	            existing.setName(name);
219	            existing.setDescription(map.getOrDefault("Description", existing.getDescription()));
220	            if (map.containsKey("Credit Hours")) {
221	                try { existing.setCreditHours(Integer.parseInt(map.get("Credit Hours"))); } catch (NumberFormatException ignored) {}
222	            }
223	            courseRepo.save(existing);
224	        } else {
225	            TrainingCourse course = new TrainingCourse();
226	            course.setCode(code);
227	            course.setName(name);
228	            course.setDescription(map.get("Description"));
229	            if (map.containsKey("Credit Hours")) {
230	                try { course.setCreditHours(Integer.parseInt(map.get("Credit Hours"))); } catch (NumberFormatException ignored) {}
231	            }
232	            course.setMandatory("Yes".equalsIgnoreCase(map.get("Mandatory")));
233	            course.setActive(!"No".equalsIgnoreCase(map.get("Active")));
234	            courseRepo.save(course);
235	        }
236	    }
237	
238	    private String requireField(Map<String, String> map, String field, int rowIndex) {
239	        String val = map.get(field);
240	        if (val == null || val.isBlank()) {
241	            throw new RuntimeException("Missing required field '" + field + "'");
242	        }
243	        return val.trim();
244	    }
245	
246	    private Map<String, String> zipToMap(String[] header, String[] row) {
247	        Map<String, String> map = new LinkedHashMap<>();
248	        for (int i = 0; i < header.length; i++) {
249	            map.put(header[i].trim(), i < row.length ? (row[i] != null ? row[i].trim() : "") : "");
250	        }
251	        return map;
252	    }
253	
254	    private List<String[]> readExcel(Path path) throws IOException {
255	        List<String[]> rows = new ArrayList<>();
256	        try (InputStream is = Files.newInputStream(path); Workbook wb = new XSSFWorkbook(is)) {
257	            Sheet sheet = wb.getSheetAt(0);
258	            for (Row row : sheet) {
259	                String[] cells = new String[row.getLastCellNum()];
260	                for (int i = 0; i < cells.length; i++) {
261	                    Cell cell = row.getCell(i);
262	                    cells[i] = cell != null ? getCellStringValue(cell) : "";
263	                }
264	                rows.add(cells);
265	            }
266	        }
267	        return rows;
268	    }
269	
270	    private String getCellStringValue(Cell cell) {
271	        return switch (cell.getCellType()) {
272	            case STRING -> cell.getStringCellValue();
273	            case NUMERIC -> String.valueOf((long) cell.getNumericCellValue());
274	            case BOOLEAN -> String.valueOf(cell.getBooleanCellValue());
275	            default -> "";
276	        };
277	    }
278	
279	    private List<String[]> readCsv(Path path) throws IOException {
280	        List<String[]> rows = new ArrayList<>();
281	        try (BufferedReader br = Files.newBufferedReader(path)) {
282	            String line;
283	            while ((line = br.readLine()) != null) {
284	                rows.add(parseCsvLine(line));
285	            }
286	        }
287	        return rows;
288	    }
289	
290	    private String[] parseCsvLine(String line) {
291	        List<String> fields = new ArrayList<>();
292	        StringBuilder sb = new StringBuilder();
293	        boolean inQuotes = false;
294	        for (int i = 0; i < line.length(); i++) {
295	            char c = line.charAt(i);
296	            if (c == '"') {
297	                if (inQuotes && i + 1 < line.length() && line.charAt(i + 1) == '"') {
298	                    sb.append('"');
299	                    i++;
300	                } else {
301	                    inQuotes = !inQuotes;
302	                }
303	            } else if (c == ',' && !inQuotes) {
304	                fields.add(sb.toString());
305	                sb.setLength(0);
306	            } else {
307	                sb.append(c);
308	            }
309	        }
310	        fields.add(sb.toString());
311	        return fields.toArray(new String[0]);
312	    }
313	
314	    static String computeSha256(InputStream is) throws Exception {
315	        MessageDigest digest = MessageDigest.getInstance("SHA-256");
316	        byte[] buf = new byte[8192];
317	        int n;
318	        while ((n = is.read(buf)) != -1) {
319	            digest.update(buf, 0, n);
320	        }
321	        byte[] hash = digest.digest();
322	        StringBuilder hex = new StringBuilder();
323	        for (byte b : hash) {
324	            hex.append(String.format("%02x", b));
325	        }
326	        return hex.toString();
327	    }
328	}
