46	    @Transactional
47	    public ExportJob queueExport(String name, String exportType, String fileFormat,
48	                                  String searchCriteriaJson, Long createdBy) {
49	        ExportJob job = new ExportJob();
50	        job.setName(name);
51	        job.setExportType(exportType);
52	        job.setFileFormat(fileFormat);
53	        job.setSearchCriteriaJson(searchCriteriaJson);
54	        job.setCreatedBy(createdBy);
55	        job.setStatus(ExportStatus.QUEUED);
56	        return exportJobRepo.save(job);
57	    }
58	
59	    @Async("exportExecutor")
60	    public void executeExport(Long jobId) {
61	        ExportJob job = exportJobRepo.findById(jobId).orElse(null);
62	        if (job == null) return;
63	
64	        job.setStatus(ExportStatus.RUNNING);
65	        job.setStartedAt(LocalDateTime.now());
66	        exportJobRepo.save(job);
67	
68	        try {
69	            Path dir = Paths.get(storagePath);
70	            Files.createDirectories(dir);
71	
72	            String timestamp = LocalDateTime.now().format(DateTimeFormatter.ofPattern("yyyyMMdd_HHmmss"));
73	            String ext = "csv".equalsIgnoreCase(job.getFileFormat()) ? ".csv" : ".xlsx";
74	            String fileName = job.getExportType() + "_" + timestamp + ext;
75	            Path filePath = dir.resolve(fileName);
76	
77	            int count;
78	            if ("csv".equalsIgnoreCase(job.getFileFormat())) {
79	                count = exportToCsv(job.getExportType(), filePath);
80	            } else {
81	                count = exportToExcel(job.getExportType(), filePath);
82	            }
83	
84	            job.setStatus(ExportStatus.COMPLETED);
85	            job.setFilePath(filePath.toString());
86	            job.setFileName(fileName);
87	            job.setRecordCount(count);
88	            job.setCompletedAt(LocalDateTime.now());
89	        } catch (Exception e) {
90	            job.setStatus(ExportStatus.FAILED);
91	            job.setErrorMessage(e.getMessage());
92	            job.setCompletedAt(LocalDateTime.now());
93	        }
94	        exportJobRepo.save(job);
95	    }
