136	    private int exportToCsv(String type, Path filePath) throws IOException {
137	        List<String[]> rows;
138	        switch (type) {
139	            case "candidates" -> rows = getCandidateCsvRows();
140	            case "collectors" -> rows = getCollectorCsvRows();
141	            case "departments" -> rows = getDepartmentCsvRows();
142	            case "courses" -> rows = getCourseCsvRows();
143	            default -> throw new RuntimeException("Unknown export type: " + type);
144	        }
145	
146	        try (PrintWriter pw = new PrintWriter(Files.newBufferedWriter(filePath))) {
147	            for (String[] row : rows) {
148	                pw.println(String.join(",", escapeCsvFields(row)));
149	            }
150	        }
151	        return rows.size() - 1; // exclude header
152	    }
