154	    private int writeCandidateRows(Sheet sheet) {
155	        Row header = sheet.createRow(0);
156	        String[] cols = {"ID", "First Name", "Last Name", "Email", "Phone", "Location",
157	                "Title", "Employer", "Years Exp", "Education", "Stage", "Tags"};
158	        for (int i = 0; i < cols.length; i++) header.createCell(i).setCellValue(cols[i]);
159	
160	        List<CandidateProfile> list = candidateRepo.findAll();
161	        for (int i = 0; i < list.size(); i++) {
162	            CandidateProfile c = list.get(i);
163	            Row row = sheet.createRow(i + 1);
164	            row.createCell(0).setCellValue(c.getId());
165	            row.createCell(1).setCellValue(c.getFirstName());
166	            row.createCell(2).setCellValue(c.getLastName());
167	            row.createCell(3).setCellValue(c.getEmail() != null ? c.getEmail() : "");
168	            row.createCell(4).setCellValue(c.getPhone() != null ? c.getPhone() : "");
169	            row.createCell(5).setCellValue(c.getLocation() != null ? c.getLocation() : "");
170	            row.createCell(6).setCellValue(c.getCurrentTitle() != null ? c.getCurrentTitle() : "");
171	            row.createCell(7).setCellValue(c.getCurrentEmployer() != null ? c.getCurrentEmployer() : "");
172	            row.createCell(8).setCellValue(c.getYearsOfExperience() != null ? c.getYearsOfExperience() : 0);
173	            row.createCell(9).setCellValue(c.getEducationLevel() != null ? c.getEducationLevel() : "");
174	            row.createCell(10).setCellValue(c.getPipelineStage().name());
175	            row.createCell(11).setCellValue(c.getTags() != null ? c.getTags() : "");
176	        }
177	        return list.size();
178	    }
