279	    private String[] escapeCsvFields(String[] fields) {
280	        String[] result = new String[fields.length];
281	        for (int i = 0; i < fields.length; i++) {
282	            String f = fields[i] != null ? fields[i] : "";
283	            if (f.contains(",") || f.contains("\"") || f.contains("\n")) {
284	                result[i] = "\"" + f.replace("\"", "\"\"") + "\"";
285	            } else {
286	                result[i] = f;
287	            }
288	        }
289	        return result;
290	    }
