3	import org.slf4j.Logger;
4	import org.slf4j.LoggerFactory;
5	import org.springframework.beans.factory.annotation.Value;
6	import org.springframework.boot.context.event.ApplicationReadyEvent;
7	import org.springframework.context.event.EventListener;
8	import org.springframework.stereotype.Component;
9	
10	import java.util.Base64;
11	
12	@Component
13	public class EncryptionKeyValidator {
14	
15	    private static final Logger log = LoggerFactory.getLogger(EncryptionKeyValidator.class);
16	
17	    @Value("${app.encryption.key:}")
18	    private String encryptionKey;
19	
20	    @EventListener(ApplicationReadyEvent.class)
21	    public void validateEncryptionKey() {
22	        if (encryptionKey == null || encryptionKey.isBlank()) {
23	            throw new IllegalStateException(
24	                    "FATAL: app.encryption.key (APP_ENCRYPTION_KEY) is not set. "
25	                    + "Biometric data cannot be encrypted without a valid AES-256 key.");
26	        }
27	        try {
28	            byte[] keyBytes = Base64.getDecoder().decode(encryptionKey);
29	            if (keyBytes.length != 32) {
30	                throw new IllegalStateException(
31	                        "FATAL: Encryption key must be 32 bytes (AES-256), got " + keyBytes.length);
32	            }
33	        } catch (IllegalArgumentException e) {
34	            throw new IllegalStateException("FATAL: Encryption key is not valid base64", e);
35	        }
36	        log.info("Encryption key validated: AES-256 ({} bytes)", 32);
37	    }
38	}
