1	package com.eaglepoint.workforce.masking;
2	
3	public final class MaskingUtil {
4	
5	    private MaskingUtil() {}
6	
7	    public static String maskToLastFour(String input) {
8	        if (input == null) return null;
9	        if (input.length() <= 4) return input;
10	        return "*".repeat(input.length() - 4) + input.substring(input.length() - 4);
11	    }
12	
13	    public static String maskEmail(String email) {
14	        if (email == null) return null;
15	        int at = email.indexOf('@');
16	        if (at <= 1) return email;
17	        return email.charAt(0) + "*".repeat(at - 1) + email.substring(at);
18	    }
19	
20	    public static String maskPhone(String phone) {
21	        if (phone == null) return null;
22	        if (phone.length() <= 4) return phone;
23	        return "*".repeat(phone.length() - 4) + phone.substring(phone.length() - 4);
24	    }
25	
26	    /** Admin sees full value; non-admin sees masked. */
27	    public static String mask(String value, boolean isAdmin) {
28	        return isAdmin ? value : maskToLastFour(value);
29	    }
30	
31	    public static String maskEmailByRole(String email, boolean isAdmin) {
32	        return isAdmin ? email : maskEmail(email);
33	    }
34	
35	    public static String maskPhoneByRole(String phone, boolean isAdmin) {
36	        return isAdmin ? phone : maskPhone(phone);
37	    }
38	}
