45	    @PostMapping("/create")
46	    @Audited(action = AuditAction.CREATE, resource = "ExportJob")
47	    public String createExport(@RequestParam String name,
48	                                @RequestParam String exportType,
49	                                @RequestParam String fileFormat,
50	                                @AuthenticationPrincipal UserDetails userDetails,
51	                                org.springframework.web.servlet.mvc.support.RedirectAttributes redirectAttrs) {
52	        Long userId = userService.findByUsername(userDetails.getUsername())
53	                .map(User::getId).orElse(0L);
54	
55	        ExportJob job = exportService.queueExport(name, exportType, fileFormat, null, userId);
56	        exportService.executeExport(job.getId());
57	
58	        redirectAttrs.addFlashAttribute("success", "Export '" + name + "' queued");
59	        return "redirect:/exports";
