74	            String contentType = job.getFileName().endsWith(".csv")
75	                    ? "text/csv" : "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet";
76	
77	            return ResponseEntity.ok()
78	                    .header(HttpHeaders.CONTENT_DISPOSITION, "attachment; filename=\"" + job.getFileName() + "\"")
79	                    .contentType(MediaType.parseMediaType(contentType))
80	                    .body(data);
81	        } catch (Exception e) {
82	            return ResponseEntity.internalServerError().build();
83	        }
