29	                            ResourceAuthorizationService authzService) {
30	        this.importService = importService;
31	        this.userService = userService;
32	        this.authzService = authzService;
33	    }
34	
35	    @GetMapping
36	    @Audited(action = AuditAction.READ, resource = "ImportJobList")
37	    public String list(Model model, Authentication auth) {
38	        Long userId = authzService.resolveUserId(auth);
39	        model.addAttribute("imports", authzService.isAdmin(auth)
40	                ? importService.findAll() : importService.findByUser(userId));
41	        return "imports/list";
42	    }
43	
44	    @PostMapping("/upload")
45	    @Audited(action = AuditAction.CREATE, resource = "ImportJob")
46	    public String upload(@RequestParam("file") MultipartFile file,
47	                          @RequestParam String importType,
48	                          @AuthenticationPrincipal UserDetails userDetails,
49	                          RedirectAttributes redirectAttrs) {
50	        Long userId = userService.findByUsername(userDetails.getUsername())
51	                .map(User::getId).orElse(0L);
52	
53	        try {
54	            String originalName = file.getOriginalFilename();
55	            if (originalName == null || (!originalName.endsWith(".csv")
56	                    && !originalName.endsWith(".xlsx") && !originalName.endsWith(".xls"))) {
57	                redirectAttrs.addFlashAttribute("error", "Only .csv, .xlsx, or .xls files are supported");
58	                return "redirect:/imports";
59	            }
60	
61	            ImportJob job = importService.prepareImport(file, importType, userId);
62	
63	            if (job.getStatus() == ImportStatus.DUPLICATE) {
64	                redirectAttrs.addFlashAttribute("error",
65	                        "Duplicate file detected. This file has already been imported.");
66	                return "redirect:/imports";
67	            }
68	
69	            importService.executeImport(job.getId());
70	            redirectAttrs.addFlashAttribute("success",
71	                    "Import of '" + originalName + "' queued for processing");
72	        } catch (Exception e) {
73	            redirectAttrs.addFlashAttribute("error", "Upload failed: " + e.getMessage());
74	        }
75	
76	        return "redirect:/imports";
77	    }
78	
79	    @GetMapping("/{id}")
80	    @Audited(action = AuditAction.READ, resource = "ImportJobDetail")
81	    public String detail(@PathVariable Long id, Model model, Authentication auth) {
82	        ImportJob job = authzService.authorizeImportJob(id, auth);
83	        model.addAttribute("job", job);
84	        return "imports/detail";
85	    }
86	}
