14	@Service
15	public class SavedSearchService {
16	
17	    private final SavedSearchRepository savedSearchRepository;
18	    private final ObjectMapper objectMapper;
19	
20	    public SavedSearchService(SavedSearchRepository savedSearchRepository, ObjectMapper objectMapper) {
21	        this.savedSearchRepository = savedSearchRepository;
22	        this.objectMapper = objectMapper;
23	    }
24	
25	    @Transactional
26	    public SavedSearch save(String name, MatchSearchRequest request, Long createdBy) {
27	        SavedSearch ss = new SavedSearch();
28	        ss.setName(name);
29	        ss.setCreatedBy(createdBy);
30	        try {
31	            ss.setSearchCriteriaJson(objectMapper.writeValueAsString(request));
32	        } catch (JsonProcessingException e) {
33	            throw new RuntimeException("Failed to serialize search criteria", e);
34	        }
35	        return savedSearchRepository.save(ss);
36	    }
37	
38	    @Transactional(readOnly = true)
39	    public List<SavedSearch> findAll() {
40	        return savedSearchRepository.findAll();
41	    }
42	
43	    @Transactional(readOnly = true)
44	    public List<SavedSearch> findByCreator(Long createdBy) {
45	        return savedSearchRepository.findByCreatedByOrderByCreatedAtDesc(createdBy);
46	    }
47	
48	    @Transactional(readOnly = true)
49	    public Optional<SavedSearch> findById(Long id) {
50	        return savedSearchRepository.findById(id);
51	    }
52	
53	    public MatchSearchRequest deserializeCriteria(String json) {
54	        try {
55	            return objectMapper.readValue(json, MatchSearchRequest.class);
56	        } catch (JsonProcessingException e) {
57	            throw new RuntimeException("Failed to deserialize search criteria", e);
58	        }
59	    }
60	
61	    @Transactional
62	    public void delete(Long id) {
63	        savedSearchRepository.deleteById(id);
64	    }
65	}
