7	import org.springframework.stereotype.Service;
8	import org.springframework.transaction.annotation.Transactional;
9	
10	import java.util.List;
11	import java.util.Optional;
12	import java.util.Set;
13	
14	@Service
15	public class TalentPoolService {
16	
17	    private final TalentPoolRepository poolRepository;
18	    private final CandidateProfileRepository candidateRepository;
19	
20	    public TalentPoolService(TalentPoolRepository poolRepository,
21	                             CandidateProfileRepository candidateRepository) {
22	        this.poolRepository = poolRepository;
23	        this.candidateRepository = candidateRepository;
24	    }
25	
26	    @Transactional(readOnly = true)
27	    public List<TalentPool> findByCreator(Long userId) {
28	        return poolRepository.findByCreatedBy(userId);
29	    }
30	
31	    @Transactional(readOnly = true)
32	    public Optional<TalentPool> findByIdWithCandidates(Long id) {
33	        return poolRepository.findByIdWithCandidates(id);
34	    }
35	
36	    @Transactional
37	    public TalentPool create(String name, String description, Long createdBy) {
38	        TalentPool pool = new TalentPool();
39	        pool.setName(name);
40	        pool.setDescription(description);
41	        pool.setCreatedBy(createdBy);
42	        return poolRepository.save(pool);
43	    }
44	
45	    @Transactional
46	    public TalentPool addCandidates(Long poolId, List<Long> candidateIds) {
47	        TalentPool pool = poolRepository.findByIdWithCandidates(poolId)
48	                .orElseThrow(() -> new RuntimeException("Talent pool not found: " + poolId));
49	        List<CandidateProfile> candidates = candidateRepository.findAllById(candidateIds);
50	        pool.getCandidates().addAll(candidates);
51	        return poolRepository.save(pool);
52	    }
53	
54	    @Transactional
55	    public TalentPool removeCandidates(Long poolId, List<Long> candidateIds) {
56	        TalentPool pool = poolRepository.findByIdWithCandidates(poolId)
57	                .orElseThrow(() -> new RuntimeException("Talent pool not found: " + poolId));
58	        Set<CandidateProfile> toRemove = new java.util.HashSet<>(candidateRepository.findAllById(candidateIds));
59	        pool.getCandidates().removeAll(toRemove);
60	        return poolRepository.save(pool);
61	    }
62	
63	    @Transactional
64	    public void delete(Long poolId) {
65	        poolRepository.deleteById(poolId);
66	    }
67	}
