1	package com.eaglepoint.workforce.crypto;
2	
3	import jakarta.persistence.AttributeConverter;
4	import jakarta.persistence.Converter;
5	import javax.crypto.Cipher;
6	import javax.crypto.spec.GCMParameterSpec;
7	import javax.crypto.spec.SecretKeySpec;
8	import java.nio.ByteBuffer;
9	import java.security.SecureRandom;
10	import java.util.Base64;
11	
12	@Converter
13	public class BiometricAttributeConverter implements AttributeConverter<byte[], byte[]> {
14	
15	    private static final String ALGORITHM = "AES/GCM/NoPadding";
16	    private static final int GCM_IV_LENGTH = 12;
17	    private static final int GCM_TAG_LENGTH = 128;
18	
19	    private static final int REQUIRED_KEY_BYTES = 32; // AES-256
20	
21	    private SecretKeySpec getKey() {
22	        String keyBase64 = System.getProperty("app.encryption.key",
23	                System.getenv("APP_ENCRYPTION_KEY"));
24	        if (keyBase64 == null || keyBase64.isBlank()) {
25	            throw new IllegalStateException(
26	                    "Biometric encryption key not configured. "
27	                    + "Set APP_ENCRYPTION_KEY env var or app.encryption.key system property "
28	                    + "with a base64-encoded 32-byte AES key.");
29	        }
30	        byte[] keyBytes;
31	        try {
32	            keyBytes = Base64.getDecoder().decode(keyBase64);
33	        } catch (IllegalArgumentException e) {
34	            throw new IllegalStateException("APP_ENCRYPTION_KEY is not valid base64", e);
35	        }
36	        if (keyBytes.length != REQUIRED_KEY_BYTES) {
37	            throw new IllegalStateException(
38	                    "APP_ENCRYPTION_KEY must decode to exactly " + REQUIRED_KEY_BYTES
39	                    + " bytes (AES-256), got " + keyBytes.length);
40	        }
41	        return new SecretKeySpec(keyBytes, "AES");
42	    }
43	
44	    @Override
45	    public byte[] convertToDatabaseColumn(byte[] attribute) {
46	        if (attribute == null) return null;
47	        try {
48	            byte[] iv = new byte[GCM_IV_LENGTH];
49	            new SecureRandom().nextBytes(iv);
50	
51	            Cipher cipher = Cipher.getInstance(ALGORITHM);
52	            GCMParameterSpec spec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
53	            cipher.init(Cipher.ENCRYPT_MODE, getKey(), spec);
54	            byte[] cipherText = cipher.doFinal(attribute);
55	
56	            ByteBuffer buffer = ByteBuffer.allocate(iv.length + cipherText.length);
57	            buffer.put(iv);
58	            buffer.put(cipherText);
59	            return buffer.array();
60	        } catch (IllegalStateException e) {
61	            throw e;
62	        } catch (Exception e) {
63	            throw new RuntimeException("Failed to encrypt biometric data", e);
64	        }
65	    }
66	
67	    @Override
68	    public byte[] convertToEntityAttribute(byte[] dbData) {
69	        if (dbData == null) return null;
70	        try {
71	            ByteBuffer buffer = ByteBuffer.wrap(dbData);
72	            byte[] iv = new byte[GCM_IV_LENGTH];
73	            buffer.get(iv);
74	            byte[] cipherText = new byte[buffer.remaining()];
75	            buffer.get(cipherText);
76	
77	            Cipher cipher = Cipher.getInstance(ALGORITHM);
78	            GCMParameterSpec spec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
79	            cipher.init(Cipher.DECRYPT_MODE, getKey(), spec);
80	            return cipher.doFinal(cipherText);
81	        } catch (IllegalStateException e) {
82	            throw e;
83	        } catch (Exception e) {
84	            throw new RuntimeException("Failed to decrypt biometric data", e);
85	        }
86	    }
87	}
