3	import org.springframework.http.ResponseEntity;
4	import org.springframework.security.core.Authentication;
5	import org.springframework.security.core.GrantedAuthority;
6	import org.springframework.web.bind.annotation.GetMapping;
7	import org.springframework.web.bind.annotation.RequestMapping;
8	import org.springframework.web.bind.annotation.RestController;
9	
10	import java.util.LinkedHashMap;
11	import java.util.Map;
12	
13	@RestController
14	@RequestMapping("/api/v1/session")
15	public class SessionApiController {
16	
17	    @GetMapping
18	    public ResponseEntity<Map<String, Object>> session(Authentication auth) {
19	        if (auth == null || !auth.isAuthenticated()) {
20	            return ResponseEntity.status(401).body(Map.of("authenticated", false));
21	        }
22	        Map<String, Object> info = new LinkedHashMap<>();
23	        info.put("authenticated", true);
24	        info.put("username", auth.getName());
25	        info.put("roles", auth.getAuthorities().stream()
26	                .map(GrantedAuthority::getAuthority).toList());
27	        return ResponseEntity.ok(info);
28	    }
29	}
