190	    private MatchSearchRequest buildRequest(Long jobProfileId, String keyword, String locationFilter,
191	                                             Integer minYearsExperience, Integer maxYearsExperience,
192	                                             String educationLevel, BooleanOperator operator,
193	                                             List<String> skillNames, List<Integer> skillMinYears,
194	                                             List<Double> skillWeights, List<Boolean> skillRequired) {
195	        MatchSearchRequest request = new MatchSearchRequest();
196	        request.setJobProfileId(jobProfileId);
197	        request.setKeyword(keyword);
198	        request.setLocationFilter(locationFilter);
199	        request.setMinYearsExperience(minYearsExperience);
200	        request.setMaxYearsExperience(maxYearsExperience);
201	        request.setEducationLevel(educationLevel);
202	        request.setOperator(operator != null ? operator : BooleanOperator.AND);
203	
204	        if (skillNames != null) {
205	            List<MatchSearchRequest.SkillCriterion> criteria = new ArrayList<>();
206	            for (int i = 0; i < skillNames.size(); i++) {
207	                String name = skillNames.get(i);
208	                if (name == null || name.isBlank()) continue;
209	                MatchSearchRequest.SkillCriterion sc = new MatchSearchRequest.SkillCriterion();
210	                sc.setSkillName(name.trim());
211	                sc.setMinYears((skillMinYears != null && i < skillMinYears.size()) ? skillMinYears.get(i) : null);
212	                sc.setWeight((skillWeights != null && i < skillWeights.size()) ? skillWeights.get(i) : 1.0);
213	                sc.setRequired(skillRequired == null || i >= skillRequired.size() || skillRequired.get(i));
214	                criteria.add(sc);
215	            }
216	            request.setSkillCriteria(criteria);
217	        }
218	
219	        return request;
220	    }
