58	    void duplicateSubmission_withClientKey_returnsSameId() throws Exception {
59	        String json = """
60	                {
61	                    "idempotencyKey": "client-key-dup-test-001",
62	                    "referenceNumber": "PAY-DUP-001",
63	                    "amount": 100.00,
64	                    "channel": "CASH"
65	                }
66	                """;
67	
68	        MvcResult r1 = mockMvc.perform(post("/api/v1/payments")
69	                        .contentType(MediaType.APPLICATION_JSON).content(json))
70	                .andExpect(status().isOk())
71	                .andReturn();
72	
73	        MvcResult r2 = mockMvc.perform(post("/api/v1/payments")
74	                        .contentType(MediaType.APPLICATION_JSON).content(json))
75	                .andExpect(status().isOk())
76	                .andReturn();
77	
78	        // Both should return the same payment ID
79	        String body1 = r1.getResponse().getContentAsString();
80	        String body2 = r2.getResponse().getContentAsString();
81	        // Extract "id": from JSON
82	        assertTrue(body1.contains("\"id\""));
