93	                    "amount": 250.50,
94	                    "channel": "CHECK",
95	                    "checkNumber": "CHK-999"
96	                }
97	                """;
98	
99	        MvcResult r1 = mockMvc.perform(post("/api/v1/payments")
100	                        .contentType(MediaType.APPLICATION_JSON).content(json))
101	                .andExpect(status().isOk())
102	                .andReturn();
