138	    private String extractId(String json) {
139	        // Simple extraction of "id":N from JSON
140	        int idx = json.indexOf("\"id\"");
141	        if (idx < 0) return "";
142	        int colon = json.indexOf(':', idx);
143	        int end = json.indexOf(',', colon);
144	        if (end < 0) end = json.indexOf('}', colon);
145	        return json.substring(colon + 1, end).trim();
146	    }
